import{_ as t,o as a,c as r,ag as o}from"./chunks/framework.OsDJF_Ea.js";const p=JSON.parse('{"title":"Getting Started","description":"","frontmatter":{},"headers":[],"relativePath":"guide/getting-started.md","filePath":"guide/getting-started.md"}'),s={name:"guide/getting-started.md"};function i(d,e,n,c,l,h){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h1><h2 id="what-is-insposearch" tabindex="-1">What is InspoSearch <a class="header-anchor" href="#what-is-insposearch" aria-label="Permalink to &quot;What is InspoSearch&quot;">​</a></h2><p>InspoSearch is an open-source multi-source visual research engine. It searches <strong>500+ cultural heritage sources</strong> — museums, archives, libraries, photography collections, and open image providers — returning over <strong>3 billion images</strong> through a single search bar.</p><p>The app runs entirely in the browser. No account, no backend, no tracking. API keys for optional sources stay in <code>localStorage</code> on your machine.</p><p><span class="custom-badge">AGPL-3.0</span></p><p><a href="https://insposearch.pages.dev" target="_blank" rel="noreferrer">Open the app</a></p><h2 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;Quick Start&quot;">​</a></h2><p>Open <code>index.html</code> in a browser, or:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span></span></code></pre></div><p>That&#39;s it. No build step, no configuration.</p><h2 id="how-to-search" tabindex="-1">How to Search <a class="header-anchor" href="#how-to-search" aria-label="Permalink to &quot;How to Search&quot;">​</a></h2><ol><li>Type a query in the search bar — <code>vermeer</code>, <code>ukiyo-e</code>, <code>brutalist architecture</code></li><li>Press <code>Enter</code>. Results stream in from all enabled sources</li><li>Click any image to open the detail view with metadata and source link</li><li>Use the source filter to toggle categories or individual sources</li></ol><h2 id="search-modes" tabindex="-1">Search Modes <a class="header-anchor" href="#search-modes" aria-label="Permalink to &quot;Search Modes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mode</th><th>Behaviour</th></tr></thead><tbody><tr><td><strong>Exact</strong></td><td>Matches your terms precisely. Best for known subjects</td></tr><tr><td><strong>Explore</strong></td><td>Casts a wider net across sources. Best for visual discovery</td></tr></tbody></table><p>Toggle between modes using the mode switcher in the search bar.</p><h2 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h2><h3 id="board-view" tabindex="-1">Board View <a class="header-anchor" href="#board-view" aria-label="Permalink to &quot;Board View&quot;">​</a></h3><p>Pin images to a freeform canvas. Arrange, group, and compare results from different sources side by side. Boards persist in <code>localStorage</code>.</p><h3 id="deep-zoom" tabindex="-1">Deep Zoom <a class="header-anchor" href="#deep-zoom" aria-label="Permalink to &quot;Deep Zoom&quot;">​</a></h3><p>IIIF-compatible images open in an OpenSeadragon viewer. Examine high-resolution works at brushstroke level. Pan and zoom with mouse or keyboard.</p><h3 id="colour-extraction" tabindex="-1">Colour Extraction <a class="header-anchor" href="#colour-extraction" aria-label="Permalink to &quot;Colour Extraction&quot;">​</a></h3><p>Every result has its dominant colours extracted automatically. Filter the entire result set by palette. Useful for finding works by colour relationship rather than subject.</p><h3 id="_3d-constellation" tabindex="-1">3D Constellation <a class="header-anchor" href="#_3d-constellation" aria-label="Permalink to &quot;3D Constellation&quot;">​</a></h3><p>Visualise results as a three-dimensional point cloud based on visual similarity. Navigate the constellation to discover unexpected connections between works.</p><h3 id="cross-reference-interpret" tabindex="-1">Cross-Reference (Interpret) <a class="header-anchor" href="#cross-reference-interpret" aria-label="Permalink to &quot;Cross-Reference (Interpret)&quot;">​</a></h3><p>Select any image and trigger Interpret to cross-reference it against all sources. Find related works, trace provenance, and build context around a single piece.</p><h3 id="ai-research-assistant" tabindex="-1">AI Research Assistant <a class="header-anchor" href="#ai-research-assistant" aria-label="Permalink to &quot;AI Research Assistant&quot;">​</a></h3><p>Optional integration with Gemini, Claude, OpenAI, or Ollama. Ask questions about an image, request deeper analysis, or generate research notes. Bring your own API key. InspoSearch works fully without AI.</p><h3 id="offline-caching" tabindex="-1">Offline Caching <a class="header-anchor" href="#offline-caching" aria-label="Permalink to &quot;Offline Caching&quot;">​</a></h3><p>Previously loaded images and metadata are cached locally. Continue browsing recent searches without a network connection.</p><h2 id="keyboard-shortcuts" tabindex="-1">Keyboard Shortcuts <a class="header-anchor" href="#keyboard-shortcuts" aria-label="Permalink to &quot;Keyboard Shortcuts&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>/</code></td><td>Focus search bar</td></tr><tr><td><code>Enter</code></td><td>Execute search</td></tr><tr><td><code>Esc</code></td><td>Close detail view / clear focus</td></tr><tr><td><code>left</code> <code>right</code></td><td>Navigate images in detail view</td></tr><tr><td><code>up</code> <code>down</code></td><td>Scroll results grid</td></tr><tr><td><code>k</code></td><td>Toggle API keys panel</td></tr><tr><td><code>s</code></td><td>Toggle source filter sidebar</td></tr><tr><td><code>b</code></td><td>Toggle board view</td></tr><tr><td><code>t</code></td><td>Scroll to top</td></tr><tr><td><code>m</code></td><td>Switch search mode (exact / explore)</td></tr><tr><td><code>i</code></td><td>Interpret (cross-reference selected image)</td></tr></tbody></table><h2 id="source-categories" tabindex="-1">Source Categories <a class="header-anchor" href="#source-categories" aria-label="Permalink to &quot;Source Categories&quot;">​</a></h2><p>InspoSearch organises its 500+ sources into eight categories:</p><table tabindex="0"><thead><tr><th>Category</th><th>Count</th></tr></thead><tbody><tr><td>Museums</td><td>212</td></tr><tr><td>Historical</td><td>75</td></tr><tr><td>Art and Design</td><td>58</td></tr><tr><td>Photography</td><td>22</td></tr><tr><td>Nature</td><td>20</td></tr><tr><td>Maps</td><td>varies</td></tr><tr><td>Fashion</td><td>varies</td></tr><tr><td>Science</td><td>varies</td></tr></tbody></table><p>See the full list on the <a href="/docs/guide/sources">Sources</a> page.</p><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="/docs/guide/sources">Sources</a> — complete source directory</li><li><a href="/docs/guide/api-keys">API Keys</a> — which sources need keys and how to add them</li><li><a href="/docs/reference/architecture">Architecture</a> — how the app works under the hood</li><li><a href="/docs/about/contributing">Contributing</a> — help improve InspoSearch</li></ul>',38)])])}const g=t(s,[["render",i]]);export{p as __pageData,g as default};
